<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">APPLICATION REVIEW</span><h1><?=e($title)?></h1></div></div><div class="admin-panel table-wrap"><table><thead><tr><th>Reference</th><th>Applicant</th><th>Position / Program</th><th>Details</th><th>Status</th><th>Review</th></tr></thead><tbody><?php foreach($rows as$x):?><tr><td><?=e($x['application_number'])?><br><small><?=e($x['applied_at'])?></small></td><td><b><?=e($x['full_name'])?></b><br><?=e($x['email'])?><br><?=e($x['phone'])?></td><td><?=e($x['title'])?></td><td><?php if($type==='jobs'):?><?=e($x['education'])?><br><?=$x['experience_years']?> years<br><a href="<?=url('admin/business-resume?id='.$x['id'])?>">Download résumé</a><?php else:?><?=e($x['institution'])?><br><?=e($x['department'].' · '.$x['study_year'])?><br><?=e(mb_strimwidth($x['why_join'],0,100,'…'))?><?php endif;?></td><td><span class="status-pill <?=e($x['status'])?>"><?=e(ucfirst($x['status']))?></span></td><td><form method="post" action="<?=url('admin/business-application-status')?>"><?=csrf_field()?><input type="hidden" name="type" value="<?=e($type)?>"><input type="hidden" name="id" value="<?=$x['id']?>"><select name="status"><?php foreach($type==='jobs'?['submitted','reviewing','shortlisted','interview','selected','rejected']:['submitted','reviewing','approved','rejected'] as$s):?><option <?=$x['status']===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><input name="note" value="<?=e($x['admin_note'])?>" placeholder="Internal note"><button class="btn small">Update</button></form></td></tr><?php endforeach;?></tbody></table></div></div></section>
